const t=document.getElementById("main-header");window.addEventListener("scroll",()=>{window.scrollY>50?(t?.style.setProperty("background","rgba(15, 23, 42, 0.95)"),t?.style.setProperty("box-shadow","0 4px 40px rgba(0, 217, 255, 0.08)")):(t?.style.removeProperty("background"),t?.style.removeProperty("box-shadow"))});window.scrollY>50&&(t?.style.setProperty("background","rgba(15, 23, 42, 0.95)"),t?.style.setProperty("box-shadow","0 4px 40px rgba(0, 217, 255, 0.08)"));const i=document.getElementById("mobile-menu-btn"),r=document.getElementById("mobile-menu");i?.addEventListener("click",()=>{r?.classList.toggle("hidden")});r?.querySelectorAll("a").forEach(e=>{e.addEventListener("click",()=>{r?.classList.add("hidden")})});const n=document.getElementById("copy-link-btn");n?.addEventListener("click",async()=>{try{await navigator.clipboard.writeText(window.location.href);const e=n.innerHTML;n.innerHTML="✓ Copied!",setTimeout(()=>{n.innerHTML=e},2e3)}catch(e){console.error("Failed to copy:",e)}});const o=document.getElementById("copy-link-btn-mobile");o?.addEventListener("click",async()=>{try{await navigator.clipboard.writeText(window.location.href);const e=o.innerHTML;o.innerHTML="✓ Copied!",setTimeout(()=>{o.innerHTML=e},2e3)}catch(e){console.error("Failed to copy:",e)}});
